import{_ as l,o as t,c as e,ai as r}from"./chunks/framework.CaiDwmc7.js";const c=JSON.parse('{"title":"03 Prompt 进阶：Few-shot、结构化输出、评估与迭代","description":"","frontmatter":{},"headers":[],"relativePath":"ai/stage-1-llm/03-prompt-advanced.md","filePath":"ai/stage-1-llm/03-prompt-advanced.md"}'),i={name:"ai/stage-1-llm/03-prompt-advanced.md"};function o(s,a,n,p,h,d){return t(),e("div",null,[...a[0]||(a[0]=[r('<h1 id="_03-prompt-进阶-few-shot、结构化输出、评估与迭代" tabindex="-1">03 Prompt 进阶：Few-shot、结构化输出、评估与迭代 <a class="header-anchor" href="#_03-prompt-进阶-few-shot、结构化输出、评估与迭代" aria-label="Permalink to “03 Prompt 进阶：Few-shot、结构化输出、评估与迭代”">​</a></h1><blockquote><p>目标：让输出更稳定、更一致，减少“同一句话问三遍三种答案”的波动。</p></blockquote><h2 id="_1-few-shot-给-1-2-个示例-效果立刻提升" tabindex="-1">1）Few-shot：给 1～2 个示例，效果立刻提升 <a class="header-anchor" href="#_1-few-shot-给-1-2-个示例-效果立刻提升" aria-label="Permalink to “1）Few-shot：给 1～2 个示例，效果立刻提升”">​</a></h2><p>使用方式：</p><ul><li>在 Prompt 中先给 <strong>输入示例</strong> 与 <strong>期望输出示例</strong></li><li>再贴入你的真实输入</li></ul><p>适合场景：</p><ul><li>固定模板输出（简历 bullet、面试题模板、日报模板）</li><li>需要统一口径（同一风格、同一栏目）</li></ul><h2 id="_2-结构化输出-让模型输出-可解析-的结果" tabindex="-1">2）结构化输出：让模型输出“可解析”的结果 <a class="header-anchor" href="#_2-结构化输出-让模型输出-可解析-的结果" aria-label="Permalink to “2）结构化输出：让模型输出“可解析”的结果”">​</a></h2><p>优先两种：</p><ul><li><strong>Markdown 固定模板</strong>（你最常用）</li><li><strong>JSON</strong>（方便程序处理，后面 Agent/工具调用会用到）</li></ul><p>示例目标（描述即可）：</p><ul><li>“只输出 JSON，不要输出任何解释文字”</li><li>“字段必须包含：title, points, pitfalls”</li></ul><h2 id="_3-评估与迭代-别凭感觉-做个小对比" tabindex="-1">3）评估与迭代：别凭感觉，做个小对比 <a class="header-anchor" href="#_3-评估与迭代-别凭感觉-做个小对比" aria-label="Permalink to “3）评估与迭代：别凭感觉，做个小对比”">​</a></h2><p>最小评估办法：</p><ul><li>用同一段输入，准备 2～3 个 Prompt 版本</li><li>让模型输出后，你用 3 个标准打分： <ul><li><strong>完整性</strong>：是否漏点</li><li><strong>可读性</strong>：是否能直接用</li><li><strong>一致性</strong>：多次运行是否差不多</li></ul></li></ul><h2 id="_4-今日练习-30-分钟" tabindex="-1">4）今日练习（30 分钟） <a class="header-anchor" href="#_4-今日练习-30-分钟" aria-label="Permalink to “4）今日练习（30 分钟）”">​</a></h2><ul><li>选一个你常用场景：比如“生成面试题”</li><li>用 Few-shot 把输出模板固定下来</li><li>再把输出从“纯文字”改成“Markdown 固定栏目”</li></ul>',17)])])}const m=l(i,[["render",o]]);export{c as __pageData,m as default};
